import type { ComponentProps, ComponentRef } from 'react';
import {
  Collapsible as CollapsiblePrimitive,
  useCollapsible,
  useCollapsibleContext,
} from '@ark-ui/react/collapsible';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { ChevronRightIcon } from '@/lib/moduix/icons/ui';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Collapsible.module.css';

const CollapsibleRoot = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.Root>,
  ComponentProps<typeof CollapsiblePrimitive.Root>
>(function CollapsibleRoot({ className, ...props }, ref) {
  return (
    <CollapsiblePrimitive.Root
      ref={ref}
      data-slot="collapsible-root"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const CollapsibleRootProvider = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.RootProvider>,
  ComponentProps<typeof CollapsiblePrimitive.RootProvider>
>(function CollapsibleRootProvider({ className, ...props }, ref) {
  return (
    <CollapsiblePrimitive.RootProvider
      ref={ref}
      data-slot="collapsible-root-provider"
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const CollapsibleTrigger = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.Trigger>,
  ComponentProps<typeof CollapsiblePrimitive.Trigger>
>(function CollapsibleTrigger({ className, ...props }, ref) {
  return (
    <CollapsiblePrimitive.Trigger
      ref={ref}
      data-slot="collapsible-trigger"
      className={clsx(styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const CollapsibleIndicator = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.Indicator>,
  ComponentProps<typeof CollapsiblePrimitive.Indicator>
>(function CollapsibleIndicator({ className, children, ...props }, ref) {
  return (
    <CollapsiblePrimitive.Indicator
      ref={ref}
      data-slot="collapsible-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      {...props}
    >
      {children ?? <ChevronRightIcon />}
    </CollapsiblePrimitive.Indicator>
  );
});

const CollapsibleContent = forwardRef<
  ComponentRef<typeof CollapsiblePrimitive.Content>,
  ComponentProps<typeof CollapsiblePrimitive.Content>
>(function CollapsibleContent({ className, ...props }, ref) {
  return (
    <CollapsiblePrimitive.Content
      ref={ref}
      data-slot="collapsible-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const CollapsibleContext = CollapsiblePrimitive.Context;

const Collapsible = Object.assign(CollapsibleRoot, {
  Root: CollapsibleRoot,
  RootProvider: CollapsibleRootProvider,
  Trigger: CollapsibleTrigger,
  Indicator: CollapsibleIndicator,
  Content: CollapsibleContent,
  Context: CollapsibleContext,
});

export { Collapsible, useCollapsible, useCollapsibleContext };
export type {
  CollapsibleOpenChangeDetails,
  UseCollapsibleContext,
  UseCollapsibleProps,
  UseCollapsibleReturn,
} from '@ark-ui/react/collapsible';

@layer ui.components {
  @keyframes collapsible-content-open {
    from {
      height: var(--collapsed-height, 0);
      width: var(--collapsed-width, var(--width));
      opacity: var(--collapsible-content-closed-opacity, 0.01);
    }

    to {
      height: var(--height);
      width: var(--width);
      opacity: var(--collapsible-content-open-opacity, 1);
    }
  }

  @keyframes collapsible-content-closed {
    from {
      height: var(--height);
      width: var(--width);
      opacity: var(--collapsible-content-open-opacity, 1);
    }

    to {
      height: var(--collapsed-height, 0);
      width: var(--collapsed-width, var(--width));
      opacity: var(--collapsible-content-closed-opacity, 0.01);
    }
  }

  .root {
    box-sizing: border-box;
    display: flex;
    width: var(--collapsible-width, 14rem);
    max-width: var(--collapsible-max-width, 100%);
    min-width: 0;
    flex-direction: column;
    color: var(--collapsible-color, var(--color-foreground));
  }

  .trigger {
    box-sizing: border-box;
    display: flex;
    width: 100%;
    align-items: center;
    justify-content: space-between;
    gap: var(--collapsible-trigger-gap, var(--spacing-2));
    margin: 0;
    border: 0;
    border-radius: var(--collapsible-trigger-radius, 0);
    padding-block: var(--collapsible-trigger-padding-y, var(--spacing-1));
    padding-inline: var(--collapsible-trigger-padding-x, var(--spacing-2));
    background-color: var(--collapsible-trigger-bg, transparent);
    color: var(--collapsible-trigger-color, var(--collapsible-color, var(--color-foreground)));
    font: inherit;
    font-size: var(--collapsible-trigger-font-size, var(--text-sm));
    line-height: var(--collapsible-trigger-line-height, var(--line-height-text-sm));
    text-align: left;
    user-select: none;
    outline: 0;
    cursor: pointer;
    transition:
      background-color var(--collapsible-trigger-transition, var(--transition-default)),
      color var(--collapsible-trigger-transition, var(--transition-default));

    &:focus-visible {
      outline: var(--collapsible-focus-ring-width, var(--border-width-sm)) solid
        var(--collapsible-focus-ring-color, var(--color-ring));
      outline-offset: var(--collapsible-focus-ring-offset, var(--border-width-sm));
    }

    &:not(:is([disabled], [data-disabled])) {
      @media (hover: hover) {
        &:hover {
          background-color: var(
            --collapsible-trigger-bg-hover,
            var(--collapsible-trigger-bg, transparent)
          );
        }
      }

      &:active {
        background-color: var(
          --collapsible-trigger-bg-active,
          var(--collapsible-trigger-bg-hover, var(--collapsible-trigger-bg, transparent))
        );
      }
    }

    &:is([disabled], [data-disabled]) {
      opacity: var(--collapsible-disabled-opacity, var(--opacity-disabled));
      cursor: default;
    }
  }

  .indicator {
    box-sizing: border-box;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: var(--collapsible-indicator-size, 0.75rem);
    height: var(--collapsible-indicator-size, 0.75rem);
    flex-shrink: 0;
    transition: transform var(--collapsible-indicator-transition, var(--transition-default));

    & > svg {
      width: 100%;
      height: 100%;
    }

    &[data-state='open'] {
      transform: var(--collapsible-indicator-open-transform, rotate(90deg));
    }

    &[data-disabled] {
      opacity: var(--collapsible-disabled-opacity, var(--opacity-disabled));
    }
  }

  .content {
    --collapsed-height: 0;

    box-sizing: border-box;
    overflow: hidden;
    color: var(--collapsible-content-color, var(--color-muted-foreground));
    font-size: var(--collapsible-content-font-size, var(--text-sm));
    line-height: var(--collapsible-content-line-height, var(--line-height-text-sm));

    &[data-state='open'] {
      animation: collapsible-content-open
        var(--collapsible-content-transition, var(--transition-default));

      &[data-has-collapsed-size] {
        --collapsible-content-closed-opacity: var(--collapsible-content-open-opacity, 1);
      }
    }

    &[data-state='closed'] {
      animation: collapsible-content-closed
        var(--collapsible-content-transition, var(--transition-default));

      &[data-has-collapsed-size] {
        --collapsible-content-closed-opacity: var(--collapsible-content-open-opacity, 1);
      }
    }
  }
}

export { Collapsible, useCollapsible, useCollapsibleContext } from './Collapsible';
export type {
  CollapsibleOpenChangeDetails,
  UseCollapsibleContext,
  UseCollapsibleProps,
  UseCollapsibleReturn,
} from './Collapsible';
